INSERT INTO `v1_823354f9f7d80357c8cf85d4236526f5efd81fda4a4deb28134a731519fa68ab` VALUES (2, 1000101, 1, "vo_minigame_1004_top_1_000", "vo_minigame_1004", 10001, "ふっふっふ、これでカヤぴぃとボスを見返してやるです！");
